fn ffi_balance_to_core(balance: &key_wallet_ffi::types::FFIBalance) -> WalletCoreBalance {
    // `total` is informational; WalletCoreBalance recomputes it from components.
    debug_assert_eq!(
        balance.total,
        balance.confirmed.saturating_add(balance.unconfirmed),
        "FFI balance total field diverges from components"
    );
    WalletCoreBalance::new(
        balance.confirmed,
        balance.unconfirmed,
        balance.immature,
        balance.locked,
    )
}

