fn ffi_balance_to_core(balance: &key_wallet_ffi::types::FFIBalance) -> WalletCoreBalance {
    let computed = balance.confirmed
        .saturating_add(balance.unconfirmed)
        .saturating_add(balance.immature)
        .saturating_add(balance.locked);
    if computed != balance.total {
        tracing::warn!(
            computed,
            reported = balance.total,
            "FFI balance total mismatch"
        );
    }
    WalletCoreBalance::new(
        balance.confirmed,
        balance.unconfirmed,
        balance.immature,
        balance.locked,
    )
}

